import{_ as d,o as e,c as o,ag as a}from"./chunks/framework.HG0H2VLS.js";const x=JSON.parse('{"title":"Typography","description":"","frontmatter":{},"headers":[],"relativePath":"tokens/typography.md","filePath":"tokens/typography.md"}'),i={name:"tokens/typography.md"};function c(r,t,n,s,l,h){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="typography" tabindex="-1">Typography <a class="header-anchor" href="#typography" aria-label="Permalink to &quot;Typography&quot;">​</a></h1><p>Font: <strong>Inter</strong> (loaded via Google Fonts in <code>base.css</code>).</p><h2 id="font-families" tabindex="-1">Font Families <a class="header-anchor" href="#font-families" aria-label="Permalink to &quot;Font Families&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Token</th><th>Value</th><th>Use</th></tr></thead><tbody><tr><td><code>--ai-font-title</code></td><td><code>&#39;Inter&#39;, sans-serif</code></td><td>Headings, labels, component titles</td></tr><tr><td><code>--ai-font-body</code></td><td><code>&#39;Inter&#39;, sans-serif</code></td><td>Body text, descriptions, inputs</td></tr></tbody></table><p>Both resolve to Inter — the distinction exists so a future rebrand could swap title to a different typeface without touching body text.</p><h2 id="font-weights" tabindex="-1">Font Weights <a class="header-anchor" href="#font-weights" aria-label="Permalink to &quot;Font Weights&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Token</th><th>Value</th><th>Use</th></tr></thead><tbody><tr><td><code>--ai-font-regular</code></td><td><code>400</code></td><td>Body text, descriptions</td></tr><tr><td><code>--ai-font-medium</code></td><td><code>500</code></td><td>Emphasis, pill labels, sidebar text</td></tr><tr><td><code>--ai-font-semibold</code></td><td><code>600</code></td><td>Buttons, subheadings, labels</td></tr><tr><td><code>--ai-font-bold</code></td><td><code>700</code></td><td>Headings, titles</td></tr><tr><td><code>--ai-font-extrabold</code></td><td><code>800</code></td><td>Display text (not currently used)</td></tr></tbody></table><h2 id="font-sizes-—-fixed" tabindex="-1">Font Sizes — Fixed <a class="header-anchor" href="#font-sizes-—-fixed" aria-label="Permalink to &quot;Font Sizes — Fixed&quot;">​</a></h2><p>Fixed sizes do not change between breakpoints. Use for elements that should stay the same size regardless of viewport.</p><table tabindex="0"><thead><tr><th>Token</th><th>rem</th><th>px</th><th>Style name</th><th>Use</th></tr></thead><tbody><tr><td><code>--ai-font-fixed-xxs</code></td><td><code>0.75rem</code></td><td>12px</td><td>body/xxs</td><td>Labels, captions, disclaimer text</td></tr><tr><td><code>--ai-font-fixed-xs</code></td><td><code>0.875rem</code></td><td>14px</td><td>body/xs</td><td>Small body, metadata, table cells</td></tr><tr><td><code>--ai-font-fixed-sm</code></td><td><code>1rem</code></td><td>16px</td><td>body/sm</td><td>Body text default</td></tr><tr><td><code>--ai-font-fixed-md</code></td><td><code>1.125rem</code></td><td>18px</td><td>—</td><td>Large body</td></tr><tr><td><code>--ai-font-fixed-lg</code></td><td><code>1.25rem</code></td><td>20px</td><td>—</td><td>Small heading</td></tr><tr><td><code>--ai-font-fixed-xl</code></td><td><code>1.375rem</code></td><td>22px</td><td>—</td><td>Mobile welcome title</td></tr><tr><td><code>--ai-font-fixed-2xl</code></td><td><code>1.625rem</code></td><td>26px</td><td>—</td><td>Heading 3</td></tr><tr><td><code>--ai-font-fixed-3xl</code></td><td><code>1.75rem</code></td><td>28px</td><td>—</td><td>Desktop welcome title</td></tr><tr><td><code>--ai-font-fixed-4xl</code></td><td><code>2rem</code></td><td>32px</td><td>—</td><td>Heading 1</td></tr></tbody></table><h2 id="font-sizes-—-fluid-responsive" tabindex="-1">Font Sizes — Fluid (responsive) <a class="header-anchor" href="#font-sizes-—-fluid-responsive" aria-label="Permalink to &quot;Font Sizes — Fluid (responsive)&quot;">​</a></h2><p>Fluid tokens automatically shrink at mobile breakpoints via <code>tokens-mobile.css</code> (<code>@media max-width: 639px</code>). Use for text that should scale down on small screens.</p><table tabindex="0"><thead><tr><th>Token</th><th>Desktop</th><th>Mobile (≤639px)</th><th>Use</th></tr></thead><tbody><tr><td><code>--ai-font-fluid-xxs</code></td><td><code>0.75rem</code></td><td><code>0.75rem</code></td><td>Button sm — no change</td></tr><tr><td><code>--ai-font-fluid-xs</code></td><td><code>0.875rem</code></td><td><code>0.875rem</code></td><td>Button base — no change</td></tr><tr><td><code>--ai-font-fluid-sm</code></td><td><code>1rem</code></td><td><code>0.875rem</code></td><td>Response prose</td></tr><tr><td><code>--ai-font-fluid-md</code></td><td><code>1.125rem</code></td><td><code>1rem</code></td><td>Subtitles</td></tr><tr><td><code>--ai-font-fluid-lg</code></td><td><code>1.25rem</code></td><td><code>1.125rem</code></td><td>—</td></tr><tr><td><code>--ai-font-fluid-xl</code></td><td><code>1.375rem</code></td><td><code>1.25rem</code></td><td>Section headings (Header, StyleSettings)</td></tr><tr><td><code>--ai-font-fluid-2xl</code></td><td><code>1.625rem</code></td><td><code>1.5rem</code></td><td>—</td></tr><tr><td><code>--ai-font-fluid-3xl</code></td><td><code>1.75rem</code></td><td><code>1.625rem</code></td><td>—</td></tr><tr><td><code>--ai-font-fluid-4xl</code></td><td><code>2rem</code></td><td><code>1.875rem</code></td><td>—</td></tr></tbody></table><h3 id="minimised-mode" tabindex="-1">Minimised mode <a class="header-anchor" href="#minimised-mode" aria-label="Permalink to &quot;Minimised mode&quot;">​</a></h3><p>The same fluid tokens also shrink in minimised layout (<code>data-layout=&quot;minimised&quot;</code>). Values match the mobile breakpoint but are applied via a CSS selector, not a media query — allowing compact typography in a panel context independent of screen width.</p><h2 id="line-heights" tabindex="-1">Line Heights <a class="header-anchor" href="#line-heights" aria-label="Permalink to &quot;Line Heights&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Token</th><th>rem</th><th>px</th><th>Use</th></tr></thead><tbody><tr><td><code>--ai-leading-xs</code></td><td><code>1rem</code></td><td>16px</td><td>Caption/label, button text</td></tr><tr><td><code>--ai-leading-sm</code></td><td><code>1.25rem</code></td><td>20px</td><td>Small body, suggested question title</td></tr><tr><td><code>--ai-leading-md</code></td><td><code>1.5rem</code></td><td>24px</td><td>Body text default, response prose</td></tr><tr><td><code>--ai-leading-lg</code></td><td><code>2rem</code></td><td>32px</td><td>Section headings</td></tr><tr><td><code>--ai-leading-xl</code></td><td><code>2.5rem</code></td><td>40px</td><td>Large headings</td></tr><tr><td><code>--ai-leading-2xl</code></td><td><code>3rem</code></td><td>48px</td><td>Display (not currently used)</td></tr></tbody></table><h2 id="letter-spacing-tracking" tabindex="-1">Letter Spacing (Tracking) <a class="header-anchor" href="#letter-spacing-tracking" aria-label="Permalink to &quot;Letter Spacing (Tracking)&quot;">​</a></h2><p>Tracking tokens use <code>em</code> units (relative to element font size), not <code>rem</code>.</p><table tabindex="0"><thead><tr><th>Token</th><th>Value</th><th>Figma px</th><th>Use</th></tr></thead><tbody><tr><td><code>--ai-tracking-1</code></td><td><code>-0.05em</code></td><td>-0.8px</td><td>Tightest (display headings)</td></tr><tr><td><code>--ai-tracking-2</code></td><td><code>-0.025em</code></td><td>-0.4px</td><td>Tight</td></tr><tr><td><code>--ai-tracking-3</code></td><td><code>-0.0125em</code></td><td>-0.2px</td><td>Slightly tight (WorkingIntro, code badges)</td></tr><tr><td><code>--ai-tracking-4</code></td><td><code>0em</code></td><td>0</td><td>Normal (default)</td></tr><tr><td><code>--ai-tracking-5</code></td><td><code>0.0125em</code></td><td>0.2px</td><td>Slightly loose (ChatHeader selector, disclaimer)</td></tr><tr><td><code>--ai-tracking-6</code></td><td><code>0.025em</code></td><td>0.4px</td><td>Loose</td></tr><tr><td><code>--ai-tracking-7</code></td><td><code>0.05em</code></td><td>0.8px</td><td>Loosest</td></tr></tbody></table><h2 id="named-type-styles" tabindex="-1">Named type styles <a class="header-anchor" href="#named-type-styles" aria-label="Permalink to &quot;Named type styles&quot;">​</a></h2><p>Figma uses named text styles that map to token combinations:</p><table tabindex="0"><thead><tr><th>Style name</th><th>Family</th><th>Weight</th><th>Size</th><th>Line height</th><th>Tracking</th></tr></thead><tbody><tr><td><code>title/xl</code></td><td><code>--ai-font-title</code></td><td><code>--ai-font-bold</code></td><td><code>--ai-font-fluid-xl</code></td><td><code>--ai-leading-lg</code></td><td><code>--ai-tracking-4</code></td></tr><tr><td><code>title/base</code></td><td><code>--ai-font-title</code></td><td><code>--ai-font-bold</code></td><td><code>--ai-font-fixed-sm</code></td><td><code>--ai-leading-xs</code></td><td><code>--ai-tracking-4</code></td></tr><tr><td><code>title/xs</code></td><td><code>--ai-font-title</code></td><td><code>--ai-font-semibold</code></td><td><code>--ai-font-fixed-xs</code></td><td><code>--ai-leading-xs</code></td><td><code>--ai-tracking-4</code></td></tr><tr><td><code>title/xxs</code></td><td><code>--ai-font-title</code></td><td><code>--ai-font-semibold</code></td><td><code>--ai-font-fixed-xxs</code></td><td><code>--ai-leading-xs</code></td><td><code>--ai-tracking-4</code></td></tr><tr><td><code>body/xs</code></td><td><code>--ai-font-body</code></td><td><code>--ai-font-regular</code></td><td><code>--ai-font-fixed-xs</code></td><td><code>--ai-leading-md</code></td><td><code>--ai-tracking-4</code></td></tr><tr><td><code>body/xxs</code></td><td><code>--ai-font-body</code></td><td><code>--ai-font-regular</code></td><td><code>--ai-font-fixed-xxs</code></td><td><code>--ai-leading-xs</code></td><td><code>--ai-tracking-5</code></td></tr><tr><td><code>body/xxs/medium</code></td><td><code>--ai-font-body</code></td><td><code>--ai-font-medium</code></td><td><code>--ai-font-fixed-xxs</code></td><td><code>--ai-leading-xs</code></td><td><code>--ai-tracking-5</code></td></tr><tr><td><code>button/base</code></td><td><code>--ai-font-body</code></td><td><code>--ai-font-semibold</code></td><td><code>--ai-font-fluid-xs</code></td><td><code>--ai-leading-xs</code></td><td><code>--ai-tracking-4</code></td></tr><tr><td><code>button/sm</code></td><td><code>--ai-font-body</code></td><td><code>--ai-font-semibold</code></td><td><code>--ai-font-fluid-xxs</code></td><td><code>--ai-leading-xs</code></td><td><code>--ai-tracking-4</code></td></tr></tbody></table><h2 id="figma-source" tabindex="-1">Figma source <a class="header-anchor" href="#figma-source" aria-label="Permalink to &quot;Figma source&quot;">​</a></h2><p>Typography tokens live in the <strong>Typography</strong> collection in the Design System library with three modes: Desktop, Mobile, and Minimised.</p>',25)])])}const f=d(i,[["render",c]]);export{x as __pageData,f as default};
